        /// </remarks>
        /// <exception cref="ApiException">Thrown when fails to make API call</exception>
        /// <param name="userid">The USERID identifier</param>
        /// <param name="cancellationToken">Cancellation Token to cancel the request.</param>
        /// <returns><see cref="Task"/>&lt;<see cref="IOBPv400DeleteUserApiResponse"/>&gt;</returns>
        Task<IOBPv400DeleteUserApiResponse> OBPv400DeleteUserAsync(string userid, System.Threading.CancellationToken cancellationToken = default);

