        /// <returns><see cref="Task"/>&lt;<see cref="IOBPv400GetCustomersMinimalAtAnyBankApiResponse"/>&gt;</returns>
        Task<IOBPv400GetCustomersMinimalAtAnyBankApiResponse> OBPv400GetCustomersMinimalAtAnyBankAsync(System.Threading.CancellationToken cancellationToken = default);

        /// <summary>
