        public async Task<IOBPv300GetPermissionForUserForBankAccountApiResponse?> OBPv300GetPermissionForUserForBankAccountOrDefaultAsync(string bankid, string accountid, string provider, string providerid, System.Threading.CancellationToken cancellationToken = default)
