                    IEnumerable<MediaTypeWithQualityHeaderValue> acceptHeaderValuesLocalVar = ClientUtils.SelectHeaderAcceptArray(acceptLocalVars);

                    foreach (var acceptLocalVar in acceptHeaderValuesLocalVar)
                        httpRequestMessageLocalVar.Headers.Accept.Add(acceptLocalVar);

                    httpRequestMessageLocalVar.Method = HttpMethod.Get;

                    DateTime requestedAtLocalVar = DateTime.UtcNow;

                    using (HttpResponseMessage httpResponseMessageLocalVar = await HttpClient.SendAsync(httpRequestMessageLocalVar, cancellationToken).ConfigureAwait(false))
                    {
                        ILogger<OBPv500GetUserAuthContextsApiResponse> apiResponseLoggerLocalVar = LoggerFactory.CreateLogger<OBPv500GetUserAuthContextsApiResponse>();
                        OBPv500GetUserAuthContextsApiResponse apiResponseLocalVar;

                        switch ((int)httpResponseMessageLocalVar.StatusCode) {
                            default: {
                                string responseContentLocalVar = await httpResponseMessageLocalVar.Content.ReadAsStringAsync(cancellationToken).ConfigureAwait(false);
                                apiResponseLocalVar = new(apiResponseLoggerLocalVar, httpRequestMessageLocalVar, httpResponseMessageLocalVar, responseContentLocalVar, "/obp/v5.0.0/users/{userid}/auth-context", requestedAtLocalVar, _jsonSerializerOptions);

                                break;
                            }
                        }

                        AfterOBPv500GetUserAuthContextsDefaultImplementation(apiResponseLocalVar, userid);

                        Events.ExecuteOnOBPv500GetUserAuthContexts(apiResponseLocalVar);

                        if (apiResponseLocalVar.StatusCode == (HttpStatusCode) 429)
                            foreach(TokenBase tokenBaseLocalVar in tokenBaseLocalVars)
                                tokenBaseLocalVar.BeginRateLimit();

                        return apiResponseLocalVar;
                    }
                }
            }
            catch(Exception e)
            {
                OnErrorOBPv500GetUserAuthContextsDefaultImplementation(e, "/obp/v5.0.0/users/{userid}/auth-context", uriBuilderLocalVar.Path, userid);
                Events.ExecuteOnErrorOBPv500GetUserAuthContexts(e);
                throw;
            }
        }

